/**
 * Pure (no-DB) helpers for the invite claim flow.
 *
 * Split out of [[./claim.ts]] so route files can import {@link identityMatch}
 * + {@link assertInviteClaimable} + the type/error exports without dragging
 * in `getDb` (and the `cloudflare:workers` binding) — that import poisons
 * Vite's client bundle. The DB-using helpers stay in `claim.ts`.
 */
// @lat: [[competition-invites#Claim resolution]]

import {
  COMPETITION_INVITE_ACTIVE_MARKER,
  COMPETITION_INVITE_STATUS,
  type CompetitionInvite,
  type CompetitionInviteStatus,
} from "@/db/schemas/competition-invites"

// ============================================================================
// Types
// ============================================================================

export type InviteClaimableError =
  | "not_found"
  | "expired"
  | "declined"
  | "revoked"
  | "already_paid"
  | "over_allocated"

/**
 * Result of the per-(source, championship-division) claim-time allocation
 * guardrail. Pure check — see {@link assertInviteWithinAllocation} for the
 * decision rules. The DB inputs (allocation row + accepted-paid count) are
 * resolved by the caller in [[./claim.ts]].
 */
export type InviteAllocationCheck =
  | { ok: true }
  | { ok: false; reason: "over_allocated" }

export type IdentityMatchResult =
  | { ok: true }
  | { ok: false; reason: "wrong_account" | "needs_sign_in" | "needs_sign_up" }

export interface IdentityMatchSession {
  /** `null` / `undefined` when the visitor is signed out. */
  email?: string | null
}

export interface IdentityMatchOptions {
  /**
   * Whether WODsmith has a user account matching `invite.email`. The route
   * loader supplies this by querying `userTable` — it isn't tracked on the
   * invite row because a user may sign up *later*.
   */
  accountExistsForInviteEmail: boolean
}

export class InviteNotClaimableError extends Error {
  readonly reason: InviteClaimableError
  constructor(reason: InviteClaimableError, message?: string) {
    super(message ?? `Invite is not claimable: ${reason}`)
    this.name = "InviteNotClaimableError"
    this.reason = reason
  }
}

// ============================================================================
// Helpers
// ============================================================================

function normalizeEmail(email: string): string {
  return email.trim().toLowerCase()
}

// ============================================================================
// Claimability
// ============================================================================

/**
 * Throws {@link InviteNotClaimableError} unless the invite is:
 * - status = `pending`,
 * - has a live `claimToken` and `expiresAt` in the future.
 *
 * `accepted_paid`, `declined`, `expired`, and `revoked` each map to a
 * distinct `reason` so the route can render a tailored message (and so
 * support queries can tell them apart from a generic "invalid").
 */
export function assertInviteClaimable(
  invite: CompetitionInvite,
  now: Date = new Date(),
): void {
  switch (invite.status as CompetitionInviteStatus) {
    case COMPETITION_INVITE_STATUS.PENDING:
      break
    case COMPETITION_INVITE_STATUS.ACCEPTED_PAID:
      throw new InviteNotClaimableError("already_paid")
    case COMPETITION_INVITE_STATUS.DECLINED:
      throw new InviteNotClaimableError("declined")
    case COMPETITION_INVITE_STATUS.EXPIRED:
      throw new InviteNotClaimableError("expired")
    case COMPETITION_INVITE_STATUS.REVOKED:
      throw new InviteNotClaimableError("revoked")
    default:
      throw new InviteNotClaimableError("not_found")
  }

  // Token must be live. The lookup already required a non-null token,
  // but guard against a race (e.g. webhook nulled the token between
  // resolve and assert) so we never claim a just-terminated invite.
  if (!invite.claimToken) {
    throw new InviteNotClaimableError("not_found")
  }

  if (invite.expiresAt && now >= invite.expiresAt) {
    throw new InviteNotClaimableError("expired")
  }

  if (invite.activeMarker !== COMPETITION_INVITE_ACTIVE_MARKER) {
    throw new InviteNotClaimableError("not_found")
  }
}

// ============================================================================
// Identity match
// ============================================================================

/**
 * Decide what happens next based on the visitor's session and whether a
 * WODsmith account exists for the invite's locked email.
 *
 * - signed in, session email matches invite email → `{ ok: true }`
 * - signed in, session email differs               → `wrong_account`
 * - signed out, account exists                     → `needs_sign_in`
 * - signed out, no account                         → `needs_sign_up`
 *
 * Case-insensitive on both sides via local lowercase normalization.
 */
export function identityMatch(
  session: IdentityMatchSession | null | undefined,
  invite: CompetitionInvite,
  opts: IdentityMatchOptions,
): IdentityMatchResult {
  const sessionEmail = session?.email
  const inviteEmail = normalizeEmail(invite.email)

  if (sessionEmail) {
    if (normalizeEmail(sessionEmail) === inviteEmail) {
      return { ok: true }
    }
    return { ok: false, reason: "wrong_account" }
  }

  if (opts.accountExistsForInviteEmail) {
    return { ok: false, reason: "needs_sign_in" }
  }
  return { ok: false, reason: "needs_sign_up" }
}

// ============================================================================
// Allocation guardrail (ADR-0012 Phase 5)
// ============================================================================

/**
 * Pure check: given the invite plus the resolved allocation for its
 * `(sourceId, championshipDivisionId)` and the current accepted-paid count
 * for that bucket, is there room for one more claim?
 *
 * Bespoke invites (`sourceId === null`) bypass — return `{ ok: true }`.
 *
 * `allocation` is the resolved spot count (already accounts for default
 * vs. override). `acceptedCount` is the current count of
 * `competition_invites` rows with `status === 'accepted_paid'` matching
 * `(sourceId, championshipDivisionId)`.
 *
 * `allocation === 0` is treated as "no cap configured" rather than
 * "cap is zero" — the organizer hasn't allocated this division to this
 * source, but they issued an invite anyway. Over-issue at issue time is
 * allowed per ADR-0012; matching that intent at claim time means we let
 * the athlete through. This mirrors how the Sent tab falls back to a
 * raw "X accepted" string when no denominator is set.
 *
 * Returns `{ ok: false, reason: "over_allocated" }` when:
 * - `invite.sourceId !== null` AND
 * - `allocation > 0` AND
 * - `acceptedCount >= allocation`.
 *
 * Otherwise returns `{ ok: true }`.
 */
export function assertInviteWithinAllocation(args: {
  invite: { sourceId: string | null }
  allocation: number
  acceptedCount: number
}): InviteAllocationCheck {
  if (args.invite.sourceId === null) return { ok: true }
  if (args.allocation <= 0) return { ok: true }
  if (args.acceptedCount >= args.allocation) {
    return { ok: false, reason: "over_allocated" }
  }
  return { ok: true }
}

          } catch (refundError) {
            logError({
              message:
                "[Workflow] Failed to issue automatic refund (allocation-full)",
              error:
                refundError instanceof Error
                  ? refundError
                  : new Error(String(refundError)),
              attributes: {
                purchaseId,
                paymentIntentId: session.payment_intent,
              },
            })
          }
        }

        return null
      }
    }
  }

  // Create the registration
  try {
    const result = await registerForCompetition({
      competitionId,
      userId,
      divisionId,
      teamName: registrationData.teamName,
      affiliateName: registrationData.affiliateName,
      teammates: registrationData.teammates,
      isOrganizerOverride: inviteAuthorized,
    })

    // Update registration with payment info
    await db
      .update(competitionRegistrationsTable)
      .set({
        commercePurchaseId: purchaseId,
        paymentStatus: COMMERCE_PAYMENT_STATUS.PAID,
        paidAt: new Date(),
      })
      .where(eq(competitionRegistrationsTable.id, result.registrationId))

    // Store registration answers if present
    if (registrationData.answers && registrationData.answers.length > 0) {
      await db.insert(competitionRegistrationAnswersTable).values(
        registrationData.answers.map((answer) => ({
          questionId: answer.questionId,
          registrationId: result.registrationId,
          userId,
          answer: answer.answer,
        })),
      )
    }

    // Mark purchase as completed
    await db
      .update(commercePurchaseTable)
      .set({
        status: COMMERCE_PURCHASE_STATUS.COMPLETED,
        stripePaymentIntentId: session.payment_intent ?? undefined,
        completedAt: new Date(),
      })
      .where(eq(commercePurchaseTable.id, purchaseId))

    // Record payment in financial event log
    try {
      await recordPaymentCompleted({
        purchaseId,
        teamId: competition.organizingTeamId,
        totalCents: existingPurchase.totalCents,
        platformFeeCents: existingPurchase.platformFeeCents,
        stripeFeeCents: existingPurchase.stripeFeeCents,
        organizerNetCents: existingPurchase.organizerNetCents,
        stripePaymentIntentId: session.payment_intent ?? undefined,
      })
    } catch (eventErr) {
      logWarning({
        message:
          "[Workflow] Failed to record payment event (non-fatal)",
        error: eventErr,
        attributes: { purchaseId },
      })
    }

    // Record coupon redemption if present
    if (session.metadata.couponId && session.metadata.stripeCouponId) {
      try {
        await recordRedemption({
          couponId: session.metadata.couponId,
          userId,
          purchaseId,
          competitionId,
          amountOffCents: Number(session.metadata.couponDiscountCents || 0),
          stripeCouponId: session.metadata.stripeCouponId,
        })
        await cleanupStripeCoupon(session.metadata.stripeCouponId)
      } catch (couponErr) {
        logWarning({
          message: "[Workflow] Coupon redemption/cleanup failed (non-fatal)",
          error: couponErr,
          attributes: { purchaseId, couponId: session.metadata.couponId },
        })
      }
    }

    logInfo({
      message: "[Workflow] Registration created",
      attributes: {
        registrationId: result.registrationId,
        purchaseId,
        competitionId,
        userId,
      },
    })

    // Fetch user for notifications
    const user = await db.query.userTable.findFirst({
      where: eq(userTable.id, userId),
    })

    return {
      registrationId: result.registrationId,
      userId,
      competitionId,
      divisionId,
      purchaseId,
      amountTotal: session.amount_total,
      customerEmail: session.customer_email,
      userName: user
        ? `${user.firstName || ""} ${user.lastName || ""}`.trim() || null
        : null,
      competitionName: competition.name,
      divisionName: divisionRecord?.label ?? null,
      teamName: registrationData.teamName ?? null,
      registrationDivisionId: divisionId,
      registrationTeamName: registrationData.teamName ?? null,
      registrationPendingTeammates: null,
      competitionSlug: competition.slug,
      competitionStartDate: competition.startDate,
      userEmail: user?.email ?? null,
      userFirstName: user?.firstName ?? null,
      inviteId: registrationData.inviteId ?? null,
    }
  } catch (err) {
    logError({
      message: "[Workflow] Failed to create registration",
      error: err,
      attributes: { purchaseId, competitionId, userId },
    })
    await db
      .update(commercePurchaseTable)
      .set({ status: COMMERCE_PURCHASE_STATUS.FAILED })
      .where(eq(commercePurchaseTable.id, purchaseId))
    // Re-throw to trigger step retry
    throw err
  }
}

/**
 * Flip the competition invite to `accepted_paid` after the Stripe webhook
 * confirms payment and the registration row exists.
 *
 * Idempotent: guarded by status=pending so a duplicate workflow run
 * won't trip the transition twice. Safe to retry. A zero-affected-rows
 * outcome just logs — the invite may already have been paid or revoked.
 */
async function updateCompetitionInviteStatus(
  result: RegistrationStepResult,
): Promise<void> {
  if (!result.inviteId) return

  const db = getDb()
  const now = new Date()

  const updateResult = await db
    .update(competitionInvitesTable)
    .set({
      status: COMPETITION_INVITE_STATUS.ACCEPTED_PAID,
      paidAt: now,
      claimedRegistrationId: result.registrationId,
      // Null the token so a replay of the old email link short-circuits.
      claimToken: null,
      updatedAt: now,
    })
    .where(
      and(
        eq(competitionInvitesTable.id, result.inviteId),
        eq(
          competitionInvitesTable.status,
          COMPETITION_INVITE_STATUS.PENDING,
        ),
      ),
    )

  const affected =
    (updateResult as unknown as { rowsAffected?: number }).rowsAffected ??
    (updateResult as unknown as [{ affectedRows?: number }])[0]?.affectedRows ??
    0

    attributes: { purchaseId },
  })
  return null
}

if (existingPurchase.status === COMMERCE_PURCHASE_STATUS.COMPLETED) {
  logInfo({
    message: "[Workflow] Purchase already completed, skipping registration",
    attributes: { purchaseId },
  })
  return null
}

// IDEMPOTENCY CHECK 2: Check if registration already exists
// Primary: by commercePurchaseId (set after registerForCompetition + update)
const existingRegistration =
  await db.query.competitionRegistrationsTable.findFirst({
    where: eq(competitionRegistrationsTable.commercePurchaseId, purchaseId),
  })

// Secondary: by (eventId, userId, divisionId) to catch partial failures where
// registerForCompetition succeeded but the commercePurchaseId update failed
const existingRegByUser = !existingRegistration
  ? await db.query.competitionRegistrationsTable.findFirst({
      where: and(
        eq(competitionRegistrationsTable.eventId, competitionId),
        eq(competitionRegistrationsTable.userId, userId),
        eq(competitionRegistrationsTable.divisionId, divisionId),
      ),
    })
  : null

const regToReconcile = existingRegistration ?? existingRegByUser

if (regToReconcile) {
  logInfo({
    message:
      "[Workflow] Registration already exists for purchase, ensuring purchase completed",
    attributes: {
      purchaseId,
      registrationId: regToReconcile.id,
      matchedBy: existingRegistration ? "purchaseId" : "eventId+userId",
    },
  })
  // Ensure registration is linked to purchase and has payment info
  if (!regToReconcile.commercePurchaseId) {
    await db
      .update(competitionRegistrationsTable)
      .set({
        commercePurchaseId: purchaseId,
        paymentStatus: COMMERCE_PAYMENT_STATUS.PAID,
        paidAt: new Date(),
      })
      .where(eq(competitionRegistrationsTable.id, regToReconcile.id))
  }
  // Ensure purchase is marked as completed
  await db
    .update(commercePurchaseTable)
    .set({
      status: COMMERCE_PURCHASE_STATUS.COMPLETED,
      completedAt: new Date(),
    })
    .where(eq(commercePurchaseTable.id, purchaseId))
  return null
}

// Parse stored registration data from purchase metadata
let registrationData: {
  teamName?: string
  affiliateName?: string
  teammates?: Array<{
    email: string
    firstName?: string
    lastName?: string
    affiliateName?: string
  }>
  answers?: Array<{
    questionId: string
    answer: string
  }>
  inviteId?: string | null
} = {}

if (existingPurchase.metadata) {
  try {
    registrationData = JSON.parse(existingPurchase.metadata)
  } catch {
    logWarning({
      message: "[Workflow] Failed to parse purchase metadata",
      attributes: { purchaseId },
    })
  }
}

// Capacity check — direct DB query instead of createServerFn wrapper
const competition = await db.query.competitionsTable.findFirst({
  where: eq(competitionsTable.id, competitionId),
})

if (!competition) {
  logError({
    message: "[Workflow] Competition not found for capacity check",
    attributes: { competitionId },
  })
  return null
}

const divisionConfig = await db.query.competitionDivisionsTable.findFirst({
  where: and(
    eq(competitionDivisionsTable.competitionId, competitionId),
    eq(competitionDivisionsTable.divisionId, divisionId),
  ),
})

// Fetch division label separately for notification display
const divisionRecord = await db.query.scalingLevelsTable.findFirst({
  where: eq(scalingLevelsTable.id, divisionId),
})

const [registrations, pendingPurchases] = await Promise.all([
  db
    .select({ count: count() })
    .from(competitionRegistrationsTable)
    .where(
      and(
        eq(competitionRegistrationsTable.divisionId, divisionId),
        eq(competitionRegistrationsTable.eventId, competitionId),
        ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
      ),
    ),
  db
    .select({ count: count() })
    .from(commercePurchaseTable)
    .where(
      and(
        eq(commercePurchaseTable.competitionId, competitionId),
        eq(commercePurchaseTable.divisionId, divisionId),
        eq(commercePurchaseTable.status, COMMERCE_PURCHASE_STATUS.PENDING),
        gt(commercePurchaseTable.createdAt, new Date(Date.now() - PENDING_PURCHASE_MAX_AGE_MINUTES * 60 * 1000)),
        sql`${commercePurchaseTable.id} != ${purchaseId}`,
      ),
    ),
])

const confirmedCount = Number(registrations[0]?.count ?? 0)
const pendingCount = Number(pendingPurchases[0]?.count ?? 0)
const capacity = calculateDivisionCapacity({
  registrationCount: confirmedCount,
  pendingCount,
  divisionMaxSpots: divisionConfig?.maxSpots,
  competitionDefaultMax: competition.defaultMaxSpotsPerDivision,
})

if (capacity.isFull) {
  logError({
    message: "[Workflow] Division filled during payment - refund needed",
    attributes: {
      purchaseId,
      competitionId,
      divisionId,
      userId,
      maxSpots: capacity.effectiveMax,
      registered: capacity.totalOccupied,
    },
  })

  // Mark purchase as failed
  await db
    .update(commercePurchaseTable)
    .set({
      status: COMMERCE_PURCHASE_STATUS.FAILED,
      completedAt: new Date(),
    })
    .where(eq(commercePurchaseTable.id, purchaseId))

  // Trigger automatic refund
  if (session.payment_intent) {
    try {
      const stripe = getStripe()
      const refund = await stripe.refunds.create({
        payment_intent: session.payment_intent,
        reason: "requested_by_customer",
      })
      logInfo({
        message: "[Workflow] Refund issued for division-full scenario",
        attributes: {
          purchaseId,
          paymentIntentId: session.payment_intent,
          refundId: refund.id,
        },
      })

      // Record refund in financial event log
      try {
        await recordRefundCompleted({
          purchaseId,
          teamId: competition.organizingTeamId,
          amountCents: existingPurchase.totalCents,
          stripePaymentIntentId: session.payment_intent,
          stripeRefundId: refund.id,
          reason:
            "Division filled during payment - automatic refund",
        })
      } catch (eventErr) {
        logWarning({
          message:
            "[Workflow] Failed to record refund event (non-fatal)",
          error: eventErr,
          attributes: { purchaseId },
        })
      }
    } catch (refundError) {
      logError({
        message: "[Workflow] Failed to issue automatic refund",
        error:
          refundError instanceof Error
            ? refundError
            : new Error(String(refundError)),
        attributes: {
          purchaseId,
          paymentIntentId: session.payment_intent,
        },
      })
    }
  }

  return null
}

// Competition-wide capacity re-check
if (competition.maxTotalRegistrations != null) {
  const [compRegistrations, compPendingPurchases] = await Promise.all([
    db
      .select({ count: count() })
      .from(competitionRegistrationsTable)
      .where(
        and(
          eq(competitionRegistrationsTable.eventId, competitionId),
          ne(
            competitionRegistrationsTable.status,
            REGISTRATION_STATUS.REMOVED,
          ),
        ),
      ),
    db
      .select({ count: count() })
      .from(commercePurchaseTable)
      .where(
        and(
          eq(commercePurchaseTable.competitionId, competitionId),
          eq(commercePurchaseTable.status, COMMERCE_PURCHASE_STATUS.PENDING),
          gt(commercePurchaseTable.createdAt, new Date(Date.now() - PENDING_PURCHASE_MAX_AGE_MINUTES * 60 * 1000)),
          sql`${commercePurchaseTable.id} != ${purchaseId}`,
        ),
      ),
  ])

  const compCapacity = calculateCompetitionCapacity({
    registrationCount: Number(compRegistrations[0]?.count ?? 0),
    pendingCount: Number(compPendingPurchases[0]?.count ?? 0),
    maxTotalRegistrations: competition.maxTotalRegistrations,
  })

  if (compCapacity.isFull) {
    logError({
      message:
        "[Workflow] Competition filled during payment - refund needed",
      attributes: {
        purchaseId,
        competitionId,
        userId,
        maxTotalRegistrations: compCapacity.effectiveMax,
        registered: compCapacity.totalOccupied,
      },
    })

    await db
      .update(commercePurchaseTable)
      .set({
        status: COMMERCE_PURCHASE_STATUS.FAILED,
        completedAt: new Date(),
      })
      .where(eq(commercePurchaseTable.id, purchaseId))

    if (session.payment_intent) {
      try {
        const stripe = getStripe()
        const refund = await stripe.refunds.create({
          payment_intent: session.payment_intent,
          reason: "requested_by_customer",
        })
        logInfo({
          message:
            "[Workflow] Refund issued for competition-full scenario",
          attributes: {
            purchaseId,
            paymentIntentId: session.payment_intent,
            refundId: refund.id,
          },
        })

        // Record refund in financial event log
        try {
          await recordRefundCompleted({
            purchaseId,
            teamId: competition.organizingTeamId,
            amountCents: existingPurchase.totalCents,
            stripePaymentIntentId: session.payment_intent,
            stripeRefundId: refund.id,
            reason:
              "Competition filled during payment - automatic refund",
          })
        } catch (eventErr) {
          logWarning({
            message:
              "[Workflow] Failed to record refund event (non-fatal)",
            error: eventErr,
            attributes: { purchaseId },
          })
        }
      } catch (refundError) {
        logError({
          message: "[Workflow] Failed to issue automatic refund",
          error:
            refundError instanceof Error
              ? refundError
              : new Error(String(refundError)),
          attributes: {
            purchaseId,
            paymentIntentId: session.payment_intent,
          },
        })
      }
    }

    return null
  }
}

// If the athlete has an active claimable invite for this division, the

    } = deps

    // 1. Get competition from parent (parent already validated it's non-null)
    const parentMatch = await parentMatchPromise
    const competition = parentMatch.loaderData?.competition
    if (!competition) {
      throw notFound()
    }

    // 2. Check authentication
    const session = context.session ?? null
    if (!session) {
      // Preserve invite + divisionId so post-auth return lands back on the
      // invite-locked URL (keeps prefill + closed-window bypass intact).
      const params = new URLSearchParams()
      if (inviteToken) params.set("invite", inviteToken)
      if (invitedDivisionId) params.set("divisionId", invitedDivisionId)
      const qs = params.toString()
      throw redirect({
        to: "/sign-in",
        search: {
          redirect: `/compete/${slug}/register${qs ? `?${qs}` : ""}`,
        },
      })
    }

    // 2.5. If user canceled from Stripe, release their reservation immediately
    if (canceled === "true") {
      await cancelPendingPurchaseFn({
        data: {
          userId: session.userId,
          competitionId: competition.id,
        },
      })
    }

    // 3. Parallel fetch: existing registrations, affiliate name, waivers,
    //    questions, and (when arriving via an invite for a team division)
    //    the invitee's prior team to pre-fill teammate slots.
    const [
      {
        registeredDivisionIds,
        removedDivisionIds,
        previousAnswers,
        signedWaiverIds,
      },
      userProfile,
      { waivers },
      { questions },
      invitePrefill,
    ] = await Promise.all([
      getUserCompetitionRegistrationsFn({
        data: {
          competitionId: competition.id,
          userId: session.userId,
        },
      }),
      getUserProfileFn({
        data: { userId: session.userId },
      }),
      getCompetitionWaiversFn({
        data: { competitionId: competition.id },
      }),
      getCompetitionQuestionsFn({
        data: { competitionId: competition.id },
      }),
      inviteToken
        ? getInvitePrefillFn({ data: { slug, token: inviteToken } })
        : Promise.resolve({ priorTeam: null as null }),
    ])

    // Invite-flow short-circuit: if the URL specifies a division (the claim
    // CTA always does) and the athlete already has an active registration in
    // that division, send them to the registered confirmation page instead
    // of stranding them on the registration form. Mirrors the claim route's
    // `already_paid` redirect — covers the post-Stripe-success bounce-back
    // and any later return visit to the original claim/register URL.
    if (
      invitedDivisionId &&
      registeredDivisionIds.includes(invitedDivisionId)
    ) {
      throw redirect({
        to: "/compete/$slug/registered",
        params: { slug },
        search: { session_id: undefined, registration_id: undefined },
      })
    }

    // For public flow we deliberately do NOT redirect when registered —
    // allow registration for additional divisions.

    // 4. Check registration window (dates are now YYYY-MM-DD strings)
    const now = new Date()
    const todayStr = getLocalDateKey(now)
    const regOpensAt = competition.registrationOpensAt
    const regClosesAt = competition.registrationClosesAt

    // String comparison works for YYYY-MM-DD format
    const registrationOpen = !!(
      regOpensAt &&
      regClosesAt &&
      todayStr >= regOpensAt &&
      todayStr <= regClosesAt
    )

    // 5. Get competition settings for divisions
    const settings = parseCompetitionSettings(competition.settings)
    if (!settings?.divisions?.scalingGroupId) {
      // No divisions configured - will show error in component
      return {
        competition,
        scalingGroup: null,
        publicDivisions: [],
        competitionCapacity: null,
        userId: session.userId,
        registrationOpen,
        registrationOpensAt: regOpensAt,
        registrationClosesAt: regClosesAt,
        defaultAffiliateName: undefined,
        divisionsConfigured: false,
        waivers: [],
        questions: [],
        registeredDivisionIds: [],
        removedDivisionIds: [],
        previousAnswers: [],
        signedWaiverIds: [],
        invitePriorTeam: null,
      }
    }

    // 6. Get scaling group and levels for divisions (via server function)
    // Also get public divisions for capacity info
    const [
      { scalingGroup },
      { divisions: publicDivisions, competitionCapacity },
    ] = await Promise.all([
      getScalingGroupWithLevelsFn({
        data: { scalingGroupId: settings.divisions.scalingGroupId },
      }),
      getPublicCompetitionDivisionsFn({
        data: { competitionId: competition.id },
      }),
    ])

    if (
      !scalingGroup ||
      !scalingGroup.scalingLevels ||
      scalingGroup.scalingLevels.length === 0
    ) {
      // Divisions not properly configured - will show error in component
      return {
        competition,
        scalingGroup: null,
        publicDivisions: [],
        competitionCapacity: null,
        userId: session.userId,
        registrationOpen,
        registrationOpensAt: regOpensAt,
        registrationClosesAt: regClosesAt,
        defaultAffiliateName: undefined,
        divisionsConfigured: false,
        waivers: [],
        questions: [],
        registeredDivisionIds: [],
        removedDivisionIds: [],
        previousAnswers: [],
        signedWaiverIds: [],
        invitePriorTeam: null,
      }
    }

    return {
      competition,
      scalingGroup,
      publicDivisions,
      competitionCapacity: competitionCapacity ?? null,
      userId: session.userId,
      registrationOpen,
      registrationOpensAt: regOpensAt,
      registrationClosesAt: regClosesAt,
      defaultAffiliateName: userProfile.affiliateName ?? undefined,
      divisionsConfigured: true,
      waivers,
      questions,
      userFirstName: userProfile.firstName,
      userLastName: userProfile.lastName,
      userEmail: userProfile.email,
      registeredDivisionIds,
      removedDivisionIds,
      previousAnswers,
      signedWaiverIds,
      invitePriorTeam: invitePrefill.priorTeam,
    }
  },
})

function RegisterPage() {
  const {
    competition,
    scalingGroup,
    publicDivisions,
    competitionCapacity,
    userId,
    registrationOpen,
    registrationOpensAt,
    registrationClosesAt,
    defaultAffiliateName,
    divisionsConfigured,
    waivers,
    questions,
    userFirstName,
    userLastName,
    userEmail,
    registeredDivisionIds,
    removedDivisionIds,
    previousAnswers,
    signedWaiverIds,
    invitePriorTeam,
  } = Route.useLoaderData()

  const {
    canceled,
    divisionId: initialDivisionId,
    invite: inviteToken,
  } = Route.useSearch()

  // Show error if divisions are not configured
  if (!divisionsConfigured || !scalingGroup) {
    return (
      <div className="mx-auto max-w-2xl">
        <div className="bg-destructive/10 rounded-lg border border-destructive/20 p-6">
          <h1 className="text-2xl font-bold mb-2">
            Registration Not Available
          </h1>
          <p>
            {!divisionsConfigured
              ? "This competition does not have divisions configured yet."
              : "This competition's divisions are not properly configured."}
          </p>
        </div>

