/**
 * Competition invite claim landing route.
 *
 * The athlete clicks the `/compete/$slug/claim/$token` link in the email.
 * The loader:
 *   1. resolves the invite via `getInviteByTokenFn` (hashes + looks up),
 *   2. runs `identityMatch` against the current session,
 *   3. branches — redirect for sign-in / sign-up, render rejection for
 *      wrong account, render error for expired / declined / revoked, or
 *      render the claim page for the happy path.
 *
 * The claim page itself is thin in Phase 2: it confirms the invite and
 * sends the athlete into the existing registration flow at
 * `/compete/$slug/register?divisionId=<x>`. Phase 2 sub-arc C extends
 * `initiateRegistrationPaymentFn` to accept `inviteToken` so the paid
 * registration flips the invite to `accepted_paid`.
 */

import { createFileRoute, Link, redirect } from "@tanstack/react-router"
import { AlertCircle, CheckCircle2, LogOut, Ticket, UserX } from "lucide-react"
import { useState } from "react"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  type InviteClaimableError,
  identityMatch,
} from "@/server/competition-invites/identity"
import { logoutFn } from "@/server-fns/auth-fns"
import { getInviteByTokenFn } from "@/server-fns/competition-invite-fns"

type Branch =
  | {
      kind: "claimable"
      divisionId: string
      divisionLabel: string
      championshipName: string
    }
  | {
      kind: "wrong_account"
      championshipName: string
      inviteEmail: string
      accountExistsForInviteEmail: boolean
    }
  | {
      kind: "already_claimed"
      championshipName: string
      registrationId: string
    }
  | {
      kind: "over_allocated"
      championshipName?: string
    }
  | { kind: "invalid"; reason: InviteClaimableError; championshipName?: string }

export const Route = createFileRoute("/compete/$slug/claim/$token")({
  component: ClaimPage,
  staleTime: 0,
  loader: async ({ params, context, parentMatchPromise }): Promise<Branch> => {
    const result = await getInviteByTokenFn({
      data: { slug: params.slug, token: params.token },
    })

    if (result.kind === "not_claimable") {
      // Already-registered athletes shouldn't see a destructive "error" page —
      // they're not in an error state, they just landed on the wrong page.
      // Send them to their registration view. Covers both an invite that was
      // already consumed (status = accepted_paid) and the cross-check against
      // an active registration created via any lane.
      if (result.reason === "already_paid") {
        throw redirect({
          to: "/compete/$slug/registered",
          params: { slug: params.slug },
          search: { session_id: undefined, registration_id: undefined },
        })
      }

      // ADR-0012 Phase 5: source-attributed allocation filled. Render a
      // soft (info-style) page rather than a destructive error — the
      // athlete isn't at fault, the spot just isn't available from this
      // source for this division.
      if (result.reason === "over_allocated") {
        return {
          kind: "over_allocated",
          championshipName:
            "championshipName" in result ? result.championshipName : undefined,
        }
      }

      // `not_found` happens both when the link is bogus AND when the original
      // invite has been consumed and the token hash nulled (replay-safe). To
      // tell them apart, peek at the parent route's `userRegistrations`: if
      // the signed-in visitor already has an active registration in this
      // competition, render the friendly "already claimed" page instead of
      // the generic invalid-link error.
      if (result.reason === "not_found" && context.session) {
        const parentMatch = await parentMatchPromise
        const userRegistrations = parentMatch.loaderData?.userRegistrations
        const competition = parentMatch.loaderData?.competition
        const firstRegistration = userRegistrations?.[0]
        if (competition && firstRegistration) {
          return {
            kind: "already_claimed",
            championshipName: competition.name,
            registrationId: firstRegistration.id,
          }
        }
      }

      return {
        kind: "invalid",
        reason: result.reason,
        championshipName:
          "championshipName" in result ? result.championshipName : undefined,
      }
    }

    const session = context.session ?? null
    const match = identityMatch(
      session?.user ? { email: session.user.email } : null,
      result.invite,
      { accountExistsForInviteEmail: result.accountExistsForInviteEmail },
    )

    if (match.ok) {
      return {
        kind: "claimable",
        divisionId: result.invite.championshipDivisionId,
        divisionLabel: result.divisionLabel,
        championshipName: result.championshipName,
      }
    }

    if (match.reason === "wrong_account") {
      return {
        kind: "wrong_account",
        championshipName: result.championshipName,
        inviteEmail: result.invite.email,
        accountExistsForInviteEmail: result.accountExistsForInviteEmail,
      }
    }

    // Signed out — redirect into sign-in / sign-up with email pre-filled and
    // the invite token so the post-auth flow re-runs the claim.
    const authPath = match.reason === "needs_sign_in" ? "/sign-in" : "/sign-up"
    throw redirect({
      to: authPath,
      search: {
        redirect: `/compete/${params.slug}/claim/${params.token}`,
        email: result.invite.email,
        invite: params.token,
      },
    })
  },
})

function ClaimPage() {
  const { slug, token } = Route.useParams()
  const data = Route.useLoaderData()

  if (data.kind === "invalid") {
    return (
      <InvalidInvite
        reason={data.reason}
        championshipName={data.championshipName}
      />
    )
  }

  if (data.kind === "wrong_account") {
    return (
      <WrongAccount
        slug={slug}
        token={token}
        championshipName={data.championshipName}
        inviteEmail={data.inviteEmail}
        accountExistsForInviteEmail={data.accountExistsForInviteEmail}
      />
    )
  }

  if (data.kind === "already_claimed") {
    return (
      <AlreadyClaimed
        slug={slug}
        championshipName={data.championshipName}
        registrationId={data.registrationId}
      />
    )
  }

  if (data.kind === "over_allocated") {
    return <OverAllocated championshipName={data.championshipName} />
  }

  return (
    <ClaimablePage
      slug={slug}
      token={token}
      divisionId={data.divisionId}
      divisionLabel={data.divisionLabel}
      championshipName={data.championshipName}
    />
  )
}

// ============================================================================
// Branch components
// ============================================================================

function ClaimablePage(props: {
  slug: string
  token: string
  divisionId: string
  divisionLabel: string
  championshipName: string
}) {
  return (
    <div className="mx-auto max-w-xl px-4 py-12">
      <Card>
        <CardHeader>
          <div className="mx-auto mb-2 flex h-12 w-12 items-center justify-center rounded-full bg-primary/10">
            <CheckCircle2 className="h-7 w-7 text-primary" />
          </div>

.inputValidator((data: unknown) => getInviteByTokenInputSchema.parse(data))
.handler(async ({ data }) => {
  return withRequestContext(
    {
      serverFn: "getInviteByTokenFn",
      attributes: { slug: data.slug, tokenLast4: data.token.slice(-4) },
    },
    async () => {
      const invite = await resolveInviteByToken(data.token)
      if (!invite) {
        logInfo({
          message: "[Invites] Claim token did not resolve",
          attributes: { slug: data.slug, tokenLast4: data.token.slice(-4) },
        })
        return {
          kind: "not_claimable" as const,
          reason: "not_found" as InviteClaimableError,
        }
      }

      const db = getDb()

      // Verify the token's invite belongs to the competition in the URL.
      // Anti-typo guard: if a user mis-pastes a link they'd otherwise get
      // a confusing "right competition, wrong invite" experience.
      const [champ] = await db
        .select({
          id: competitionsTable.id,
          slug: competitionsTable.slug,
          name: competitionsTable.name,
        })
        .from(competitionsTable)
        .where(eq(competitionsTable.id, invite.championshipCompetitionId))
        .limit(1)

      if (!champ || champ.slug !== data.slug) {
        logWarning({
          message: "[Invites] Token slug mismatch",
          attributes: {
            slug: data.slug,
            tokenLast4: data.token.slice(-4),
            inviteChampionshipId: invite.championshipCompetitionId,
          },
        })
        return {
          kind: "not_claimable" as const,
          reason: "not_found" as InviteClaimableError,
        }
      }

      try {
        assertInviteClaimable(invite)
      } catch (err) {
        if (err instanceof InviteNotClaimableError) {
          return {
            kind: "not_claimable" as const,
            reason: err.reason,
            championshipName: champ.name,
          }
        }
        throw err
      }

      const [division, account, session] = await Promise.all([
        db
          .select({
            id: scalingLevelsTable.id,
            label: scalingLevelsTable.label,
          })
          .from(scalingLevelsTable)
          .where(eq(scalingLevelsTable.id, invite.championshipDivisionId))
          .limit(1)
          .then((rows) => rows[0] ?? null),
        db
          .select({ id: userTable.id })
          .from(userTable)
          .where(eq(userTable.email, normalizeInviteEmail(invite.email)))
          .limit(1)
          .then((rows) => rows[0] ?? null),
        getSessionFromCookie(),
      ])

      // Cross-check: if the visitor is signed in as the invited identity and
      // already has an active registration for this (competition, division),
      // short-circuit to "already_paid" regardless of which lane (public,
      // organizer-manual, prior invite claim) created that registration.
      const sessionEmail = session?.user?.email
      if (
        sessionEmail &&
        normalizeInviteEmail(sessionEmail) ===
          normalizeInviteEmail(invite.email)
      ) {
        const [existingReg] = await db
          .select({ id: competitionRegistrationsTable.id })
          .from(competitionRegistrationsTable)
          .where(
            and(
              eq(
                competitionRegistrationsTable.eventId,
                invite.championshipCompetitionId,
              ),
              eq(competitionRegistrationsTable.userId, session.userId),
              eq(
                competitionRegistrationsTable.divisionId,
                invite.championshipDivisionId,
              ),
              ne(
                competitionRegistrationsTable.status,
                REGISTRATION_STATUS.REMOVED,
              ),
            ),
          )
          .limit(1)
        if (existingReg) {
          return {
            kind: "not_claimable" as const,
            reason: "already_paid" as InviteClaimableError,
            championshipName: champ.name,
          }
        }
      }

      // ADR-0012 Phase 5: per-(source, division) allocation guardrail.
      // Best-effort UX gate — the authoritative re-check lives in the
      // Stripe workflow at payment confirmation. Bespoke invites
      // (sourceId IS NULL) bypass. The occupied count includes both
      // accepted_paid invites AND in-flight Stripe checkouts (held for
      // PENDING_PURCHASE_MAX_AGE_MINUTES) so two athletes can't both pass
      // the gate while one is mid-payment.
      if (invite.sourceId) {

  const itemDiscount = validatedCoupon
    ? Math.round(couponDiscount * itemProportion)
    : 0
  const purchaseId = createCommercePurchaseId()
  purchaseIds.push(purchaseId)

  await db.insert(commercePurchaseTable).values({
    id: purchaseId,
    userId,
    productId: product.id,
    status: COMMERCE_PURCHASE_STATUS.PENDING,
    competitionId: input.competitionId,
    divisionId: item.divisionId,
    totalCents: feeBreakdown.totalChargeCents,
    platformFeeCents: feeBreakdown.platformFeeCents,
    stripeFeeCents: feeBreakdown.stripeFeeCents,
    organizerNetCents: feeBreakdown.organizerNetCents,
    metadata: JSON.stringify({
      teamName: item.teamName,
      affiliateName: input.affiliateName,
      teammates: item.teammates,
      answers: input.answers,
      couponCode: input.couponCode,
      couponDiscountCents: itemDiscount,
      inviteId:
        inviteIdForPurchase &&
        item.divisionId === inviteDivisionIdForPurchase
          ? inviteIdForPurchase
          : null,
    }),
  })

  totalChargeCents += feeBreakdown.totalChargeCents
  totalOrganizerNetCents += feeBreakdown.organizerNetCents

  // Get division label for Stripe line item
  const division = await db.query.scalingLevelsTable.findFirst({
    where: eq(scalingLevelsTable.id, item.divisionId),
  })

  lineItems.push({
    price_data: {
      currency: "usd",
      unit_amount: feeBreakdown.totalChargeCents,
      product_data: {
        name: `${competition.name} - ${division?.label ?? "Registration"}`,
        description: "Competition Registration",
      },
    },
    quantity: 1,
  })
}

// If no paid items remain (all were free after splitting), return
if (purchaseIds.length === 0 || lineItems.length === 0) {
  return {
    purchaseId: null,
    checkoutUrl: null,
    totalCents: 0,
    isFree: true,
    registrationId: null,
  }
}

// 9. Create Stripe Checkout Session with multiple line items
const appUrl = getAppUrl()
const sessionParams: Stripe.Checkout.SessionCreateParams = {
  mode: "payment",
  payment_method_types: ["card"],
  line_items: lineItems,
  metadata: {
    purchaseIds: purchaseIds.join(","),
    userId,
    competitionId: input.competitionId,
    type: COMMERCE_PRODUCT_TYPE.COMPETITION_REGISTRATION,
    multiDivision: purchaseIds.length > 1 ? "true" : "false",
  },
  success_url: `${appUrl}/compete/${competition.slug}/registered?session_id={CHECKOUT_SESSION_ID}`,
  cancel_url: `${appUrl}/compete/${competition.slug}/register?canceled=true`,
  expires_at: Math.floor(Date.now() / 1000) + 30 * 60,
  customer_email: session.user.email ?? undefined,
}

// Add transfer_data if organizer has verified Stripe connection
if (
  organizingTeam?.stripeConnectedAccountId &&
  organizingTeam.stripeAccountStatus === "VERIFIED"
) {
  const applicationFeeAmount = Math.max(
    0,
    totalChargeCents - totalOrganizerNetCents,
  )

  sessionParams.payment_intent_data = {
    application_fee_amount: applicationFeeAmount,
    transfer_data: {
      destination: organizingTeam.stripeConnectedAccountId,
    },
  }
}

// Create transient Stripe coupon and attach to session if applicable
if (validatedCoupon && couponDiscount > 0) {
  const stripeCouponId = `wod-${validatedCoupon.id}-${purchaseIds[0]}`
  await getStripe().coupons.create({
    id: stripeCouponId,
    amount_off: couponDiscount,
    currency: "usd",
    duration: "once",
    max_redemptions: 1,
    metadata: { couponId: validatedCoupon.id, purchaseId: purchaseIds[0] },
  })
  sessionParams.discounts = [{ coupon: stripeCouponId }]
  sessionParams.metadata = {
    ...sessionParams.metadata,
    couponId: validatedCoupon.id,
    stripeCouponId,
    couponCode: input.couponCode ?? "",
    couponDiscountCents: couponDiscount.toString(),
  }

/**
 * Per-(source, championship-division) allocation resolution.
 *
 * ADR-0012 Phase 1: pure functional helper plus a DB read used by the
 * organizer-invites loader. The resolver applies the
 * default-plus-override pattern (source default → per-division override),
 * preserving the existing series math when no override is set.
 *
 * The resolver is intentionally pure — the caller passes in the source row,
 * the championship's divisions, and the allocation rows already loaded
 * from the DB. This keeps it easy to unit-test against ADR-0011's
 * roster fixtures without standing up a database.
 */
// @lat: [[competition-invites#Sources schema]]

import "server-only"

import { eq, inArray } from "drizzle-orm"
import { getDb } from "@/db"
import {
  COMPETITION_INVITE_SOURCE_KIND,
  type CompetitionInviteSource,
  type CompetitionInviteSourceDivisionAllocation,
  competitionInviteSourceDivisionAllocationsTable,
  competitionInviteSourcesTable,
} from "@/db/schemas/competition-invites"

// ============================================================================
// Types
// ============================================================================

export interface ChampionshipDivision {
  id: string
  label: string
}

export interface ResolvedSourceAllocations {
  /** Total contributed by this source across the championship's divisions. */
  total: number
  /** Per-championship-division breakdown — keyed by championshipDivisionId. */
  byDivision: Record<string, number>
}

// ============================================================================
// Resolution
// ============================================================================

/**
 * Default allocation for a championship division when no override row
 * exists for `(source.id, division.id)`.
 *
 * - `kind = "competition"`: the source's `globalSpots` (Top N qualifies),
 *   applied per division. Null collapses to 0.
 * - `kind = "series"`: `directSpotsPerComp * seriesCompCount + globalSpots`,
 *   applied per division. This preserves ADR-0011's series math while
 *   distributing it equally per division by default — when the organizer
 *   wants different per-division counts they create override rows.
 */
function sourceDefaultPerDivision(
  source: CompetitionInviteSource,
  seriesCompCount: number | undefined,
): number {
  const globalSpots = source.globalSpots ?? 0
  if (source.kind === COMPETITION_INVITE_SOURCE_KIND.SERIES) {
    const direct = source.directSpotsPerComp ?? 0
    const compCount = seriesCompCount ?? 0
    return direct * compCount + globalSpots
  }
  return globalSpots
}

/**
 * Resolve per-championship-division allocations for one source, applying
 * the default-plus-override pattern. Returns the per-division map plus the
 * total contributed by this source across the championship.
 *
 * `allocations` should already be filtered to rows for `source.id` (the
 * helper does not re-filter — passing rows for other sources is a caller
 * bug, not a resolver bug). Empty `championshipDivisions` returns
 * `{ total: 0, byDivision: {} }`.
 */
export function resolveSourceAllocations(args: {
  source: CompetitionInviteSource
  championshipDivisions: ReadonlyArray<ChampionshipDivision>
  allocations: ReadonlyArray<CompetitionInviteSourceDivisionAllocation>
  /** For series sources: how many comps in the series (so directSpotsPerComp
   *  scales). Ignored for single-comp sources. */
  seriesCompCount?: number
}): ResolvedSourceAllocations {
  const overrideByDivisionId = new Map<string, number>()
  for (const allocation of args.allocations) {
    if (allocation.sourceId !== args.source.id) continue
    overrideByDivisionId.set(allocation.championshipDivisionId, allocation.spots)
  }

  const defaultSpots = sourceDefaultPerDivision(
    args.source,
    args.seriesCompCount,
  )

  const byDivision: Record<string, number> = {}
  let total = 0
  for (const division of args.championshipDivisions) {
    const override = overrideByDivisionId.get(division.id)
    const spots = override !== undefined ? override : defaultSpots
    byDivision[division.id] = spots
    total += spots
  }

  return { total, byDivision }
}

// ============================================================================
// DB reads
// ============================================================================

/**
 * Load all per-(source, championship-division) allocation rows for a
 * championship's sources. Returns one flat list — callers typically index
 * by `sourceId` themselves.
 *
 * Implemented as a join from `competition_invite_sources` rather than a
 * fan-out: one query, one result, the `championshipDivisionId` index on
 * the allocation table makes the per-division grouping cheap downstream.
 */
export async function listAllocationsForChampionship(args: {
  championshipCompetitionId: string
}): Promise<CompetitionInviteSourceDivisionAllocation[]> {
  const db = getDb()

  const sourceIdRows = await db
    .select({ id: competitionInviteSourcesTable.id })
    .from(competitionInviteSourcesTable)
    .where(
      eq(
        competitionInviteSourcesTable.championshipCompetitionId,
        args.championshipCompetitionId,
      ),
    )

  if (sourceIdRows.length === 0) return []

  const sourceIds = sourceIdRows.map((r) => r.id)

  return db
    .select()
    .from(competitionInviteSourceDivisionAllocationsTable)
    .where(
      inArray(
        competitionInviteSourceDivisionAllocationsTable.sourceId,
        sourceIds,
      ),
    )
}

import { beforeEach, describe, expect, it, vi } from "vitest"

// Two-row select-result queue. The bucket count helper fires two reads
// in parallel (accepted-paid invites + pending invite-driven purchases);
// the queue maps 1:1 to those reads in dispatch order.
const selectQueue: unknown[][] = []

function makeChain(): unknown {
	const chain: Record<string, unknown> = {}
	const noop = () => chain
	for (const m of ["from", "where", "innerJoin"]) {
		chain[m] = vi.fn(noop)
	}
	chain.then = (resolve: (value: unknown) => void) => {
		const next = selectQueue.shift() ?? []
		resolve(next)
		return Promise.resolve(next)
	}
	return chain
}

const fakeDb = {
	select: vi.fn(() => makeChain()),
}

vi.mock("@/db", () => ({
	getDb: vi.fn(() => fakeDb),
}))

vi.mock("cloudflare:workers", () => ({
	env: { APP_URL: "https://test.wodsmith.com" },
}))

import { getOccupiedCountForBucket } from "@/server/competition-invites/claim"

beforeEach(() => {
	selectQueue.length = 0
	fakeDb.select.mockClear()
})

// @lat: [[competition-invites#Claim resolution]]
describe("getOccupiedCountForBucket", () => {
	// Mirrors the regular division-capacity pattern: a slot in the
	// (sourceId, championshipDivisionId) bucket is occupied when an
	// invite is accepted_paid OR an athlete is mid-Stripe-checkout for
	// an invite-driven purchase. Two athletes claiming the last spot
	// must both see the in-flight hold so the second one bounces at
	// claim load instead of paying-then-refunding.
	it("sums accepted_paid invites and in-flight pending purchases in the bucket", async () => {
		// Read 1: accepted_paid invites count.
		selectQueue.push([{ count: 3 }])
		// Read 2: pending invite-driven purchases count (held spots).
		selectQueue.push([{ count: 2 }])

		const total = await getOccupiedCountForBucket({
			sourceId: "cisrc_1",
			championshipCompetitionId: "comp_champ",
			championshipDivisionId: "div_rxm",
		})

		expect(total).toBe(5)
		expect(fakeDb.select).toHaveBeenCalledTimes(2)
	})

	it("coerces string COUNT(*) values from the PlanetScale driver to numbers", async () => {
		// PlanetScale returns COUNT(*) as a string in some shapes. The
		// previous helper already used Number() — pin that the new helper
		// keeps doing so for both component reads.
		selectQueue.push([{ count: "4" }])
		selectQueue.push([{ count: "1" }])

		const total = await getOccupiedCountForBucket({
			sourceId: "cisrc_1",
			championshipCompetitionId: "comp_champ",
			championshipDivisionId: "div_rxm",
		})

		expect(total).toBe(5)
	})

	it("returns 0 when neither accepted nor pending rows exist for the bucket", async () => {
		selectQueue.push([{ count: 0 }])
		selectQueue.push([{ count: 0 }])

		const total = await getOccupiedCountForBucket({
			sourceId: "cisrc_empty",
			championshipCompetitionId: "comp_champ",
			championshipDivisionId: "div_rxm",
		})

		expect(total).toBe(0)
	})

	// The exclude trick is what makes the webhook re-check work: the
	// current purchase is still PENDING when the workflow probes the
	// bucket, so the count must subtract it. Same `id != $purchaseId`
	// pattern the regular division-capacity webhook uses.
	it("accepts excludePurchaseId so the webhook can omit its own purchase row", async () => {
		selectQueue.push([{ count: 1 }])
		selectQueue.push([{ count: 0 }])

		const total = await getOccupiedCountForBucket({
			sourceId: "cisrc_1",
			championshipCompetitionId: "comp_champ",
			championshipDivisionId: "div_rxm",
			excludePurchaseId: "cmp_self",
		})

		expect(total).toBe(1)
	})
})

  id: string
  label: string
}

/**
 * Parse a source's `divisionMappings` JSON column into a typed array.
 *
 * The column is `text` storing
 * `[{ sourceDivisionId, championshipDivisionId, spots? }]`. Returns an
 * empty array on null / malformed JSON — the caller falls back to label
 * matching, which is the common case for organizers who haven't filled
 * in mappings yet.
 */
function parseDivisionMappings(
  raw: string | null | undefined,
): DivisionMapping[] {
  if (!raw) return []
  try {
    const parsed = JSON.parse(raw)
    if (!Array.isArray(parsed)) return []
    return parsed.filter(
      (m): m is DivisionMapping =>
        typeof m === "object" &&
        m !== null &&
        typeof (m as { sourceDivisionId?: unknown }).sourceDivisionId ===
          "string" &&
        typeof (m as { championshipDivisionId?: unknown })
          .championshipDivisionId === "string",
    )
  } catch {
    return []
  }
}

/**
 * Map a source-side division id to its championship-division counterpart.
 *
 * Resolution order:
 *   1. Explicit row in the source's `divisionMappings` JSON.
 *   2. Label match against the championship's divisions
 *      (case-insensitive, trimmed) — covers the common case where the
 *      source comp uses the same division labels as the championship.
 *
 * Returns `null` when no mapping can be inferred. Callers use that as
 * the signal to skip the cutoff (i.e. include all leaderboard rows) so
 * mis-mapped divisions don't silently drop qualifying athletes.
 */
function mapSourceDivisionToChampionship(args: {
  sourceDivisionId: string
  sourceDivisionLabel: string
  divisionMappings: DivisionMapping[]
  championshipDivisions: ReadonlyArray<ChampionshipDivisionInfo>
}): string | null {
  const explicit = args.divisionMappings.find(
    (m) => m.sourceDivisionId === args.sourceDivisionId,
  )
  if (explicit) return explicit.championshipDivisionId

  const normalized = args.sourceDivisionLabel.trim().toLowerCase()
  const matched = args.championshipDivisions.find(
    (d) => d.label.trim().toLowerCase() === normalized,
  )
  return matched ? matched.id : null
}

/**
 * Resolve the (competitionId, name) tuples each source contributes:
 * single-comp source → 1 row; series source → every comp in the group.
 *
 * Returns a deduped list keyed by `competitionId` so a comp referenced
 * by both a direct source AND a series source only fetches once. The
 * first-encountered source wins for tagging.
 */
async function resolveSourceCompetitions(
  championshipId: string,
): Promise<{
  sources: CompetitionInviteSource[]
  refs: SourceCompetitionRef[]
  seriesCompCountBySourceId: Map<string, number>
}> {
  const sources = await listSourcesForChampionship(championshipId)
  if (sources.length === 0) {
    return { sources: [], refs: [], seriesCompCountBySourceId: new Map() }
  }

  const db = getDb()

  // Collect all comp ids we need to look up.
  const directIds = sources
    .filter(
      (s): s is typeof s & { sourceCompetitionId: string } =>
        s.kind === "competition" && !!s.sourceCompetitionId,
    )
    .map((s) => s.sourceCompetitionId)
  const groupIds = sources
    .filter(
      (s): s is typeof s & { sourceGroupId: string } =>
        s.kind === "series" && !!s.sourceGroupId,
    )
    .map((s) => s.sourceGroupId)

  // One query per category; each can be empty.
  const [directComps, seriesComps] = await Promise.all([
    directIds.length > 0
      ? db
          .select({
            id: competitionsTable.id,
            name: competitionsTable.name,
            groupId: competitionsTable.groupId,
          })
          .from(competitionsTable)
          .where(inArray(competitionsTable.id, directIds))
      : Promise.resolve(
          [] as Array<{ id: string; name: string; groupId: string | null }>,
        ),
    groupIds.length > 0
      ? db
          .select({
            id: competitionsTable.id,
            name: competitionsTable.name,
            groupId: competitionsTable.groupId,
          })
          .from(competitionsTable)
          .where(inArray(competitionsTable.groupId, groupIds))
      : Promise.resolve(
          [] as Array<{ id: string; name: string; groupId: string | null }>,
        ),
  ])

  const refs: SourceCompetitionRef[] = []
  const seen = new Set<string>()
  const seriesCompCountBySourceId = new Map<string, number>()

  for (const source of sources) {
    if (source.kind === "competition" && source.sourceCompetitionId) {
      if (seen.has(source.sourceCompetitionId)) continue
      const row = directComps.find((c) => c.id === source.sourceCompetitionId)
      if (!row) continue
      seen.add(source.sourceCompetitionId)
      refs.push({
        sourceId: source.id,
        sourceKind: source.kind,
        competitionId: row.id,
        competitionName: row.name,
      })
    } else if (source.kind === "series" && source.sourceGroupId) {
      const matchingComps = seriesComps.filter(
        (c) => c.groupId === source.sourceGroupId,
      )
      seriesCompCountBySourceId.set(source.id, matchingComps.length)
      for (const c of matchingComps) {
        if (seen.has(c.id)) continue
        seen.add(c.id)
        refs.push({
          sourceId: source.id,
          sourceKind: source.kind,
          competitionId: c.id,
          competitionName: c.name,
        })
      }
    }
  }
  return { sources, refs, seriesCompCountBySourceId }
}

/**
 * Resolve every (competition, division) pair to fetch a leaderboard
 * for. Reads `competitionsTable.settings` to find each comp's scaling
 * group, then resolves levels in one batched query.
 */

export type CompetitionInviteSource = InferSelectModel<
  typeof competitionInviteSourcesTable
>

// ============================================================================
// Source × Division Allocations
// ============================================================================

/**
 * Per-(source, championship-division) override of the invite-spot allocation.
 *
 * Per ADR-0012: the source row's `globalSpots` / `directSpotsPerComp` are the
 * defaults; a row in this table means "this championship division differs
 * from the default for this source." A `spots` of `0` is meaningful — it
 * pins the division to zero from this source. Absence of the row means
 * "use the source default."
 *
 * Cascading delete on the source row is handled in
 * `apps/wodsmith-start/src/server/competition-invites/sources.ts`
 * (`deleteSource`) — no FKs per PlanetScale convention.
 */
export const competitionInviteSourceDivisionAllocationsTable = mysqlTable(
  "competition_invite_source_division_allocations",
  {
    ...commonColumns,
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(() => createCompetitionInviteSourceDivisionAllocationId())
      .notNull(),
    // Refs `competition_invite_sources.id` (no FK; cascade in helper).
    sourceId: varchar({ length: 255 }).notNull(),
    // Refs `competition_divisions.id` (scaling level id) of the championship.
    championshipDivisionId: varchar({ length: 255 }).notNull(),
    // Override allocation count. 0 means "this division gets none from this
    // source"; absence of the row means "use the source default."
    spots: int().notNull(),
  },
  (table) => [
    uniqueIndex(
      "competition_invite_source_division_allocations_source_div_unique",
    ).on(table.sourceId, table.championshipDivisionId),
    index("competition_invite_source_division_allocations_div_idx").on(
      table.championshipDivisionId,
    ),
  ],
)

export type CompetitionInviteSourceDivisionAllocation = InferSelectModel<
  typeof competitionInviteSourceDivisionAllocationsTable
>

// ============================================================================
// Invite Origin
// ============================================================================

export const COMPETITION_INVITE_ORIGIN = {
  SOURCE: "source",
  BESPOKE: "bespoke",
} as const

export type CompetitionInviteOrigin =
  (typeof COMPETITION_INVITE_ORIGIN)[keyof typeof COMPETITION_INVITE_ORIGIN]

// ============================================================================
// Invite Status
// ============================================================================

/**
 * `pending` — invite issued, token live, waiting for the athlete to claim.
 * `accepted_paid` — the athlete finished Stripe Checkout and their
 *   `competition_registrations` row exists; set by the Stripe workflow.
 * `declined` — athlete explicitly declined via the decline route.
 * `expired` — cron-sweep transitioned a past-deadline pending invite.
 * `revoked` — organizer or an R2 send revoked the R1 invite.
 *
 * No intermediate `accepted` state — the Stripe-in-flight window is still
 * `pending` until the webhook confirms payment. See ADR-0011 "Capacity Math".
 */
export const COMPETITION_INVITE_STATUS = {
  PENDING: "pending",
  ACCEPTED_PAID: "accepted_paid",
  DECLINED: "declined",
  EXPIRED: "expired",
  REVOKED: "revoked",
} as const

export type CompetitionInviteStatus =
  (typeof COMPETITION_INVITE_STATUS)[keyof typeof COMPETITION_INVITE_STATUS]

// ============================================================================
// Invite Email Delivery Status
// ============================================================================

export const COMPETITION_INVITE_EMAIL_DELIVERY_STATUS = {
  QUEUED: "queued",
  SENT: "sent",
  FAILED: "failed",
  SKIPPED: "skipped",
} as const

