/**
 * Competition Invite Sources — CRUD helpers
 *
 * Business-logic layer for `competition_invite_sources`. Each championship
 * competition has 0+ sources; each source is either a single-competition
 * reference or a series reference, never both. Division mappings and spot
 * allocations are stored per source.
 *
 * Write-time constraint: exactly one of `sourceCompetitionId` /
 * `sourceGroupId` is non-null per row. Enforced here, not at the DB
 * level, because PlanetScale does not support check constraints and we
 * want a consistent validation boundary that yields typed errors.
 */
// @lat: [[competition-invites#Sources helpers]]

import { and, asc, eq } from "drizzle-orm"
import { getDb } from "@/db"
import {
  COMPETITION_INVITE_SOURCE_KIND,
  type CompetitionInviteSource,
  type CompetitionInviteSourceKind,
  competitionInviteSourceDivisionAllocationsTable,
  competitionInviteSourcesTable,
} from "@/db/schemas/competition-invites"

// ============================================================================
// Types
// ============================================================================

export interface DivisionMapping {
  sourceDivisionId: string
  championshipDivisionId: string
  spots?: number | null
}

export interface CreateSourceInput {
  championshipCompetitionId: string
  kind: CompetitionInviteSourceKind
  sourceCompetitionId?: string | null
  sourceGroupId?: string | null
  directSpotsPerComp?: number | null
  globalSpots?: number | null
  divisionMappings?: DivisionMapping[] | null
  sortOrder?: number
  notes?: string | null
}

export interface UpdateSourceInput {
  id: string
  kind?: CompetitionInviteSourceKind
  sourceCompetitionId?: string | null
  sourceGroupId?: string | null
  directSpotsPerComp?: number | null
  globalSpots?: number | null
  divisionMappings?: DivisionMapping[] | null
  sortOrder?: number
  notes?: string | null
}

export class InviteSourceValidationError extends Error {
  constructor(message: string) {
    super(message)
    this.name = "InviteSourceValidationError"
  }
}

// ============================================================================
// Validation
// ============================================================================

/**
 * Enforce the "exactly one of sourceCompetitionId / sourceGroupId" constraint
 * and the `kind` alignment with which column is populated. Throws an
 * `InviteSourceValidationError` on violation.
 *
 * A `kind = "series"` source with no `globalSpots` / `directSpotsPerComp`
 * set is intentionally allowed — the organizer may want to set them later
 * before actually sourcing invitees.
 */
export function assertSourceReferenceValid(input: {
  kind: CompetitionInviteSourceKind
  sourceCompetitionId?: string | null
  sourceGroupId?: string | null
}): void {
  const hasComp = !!input.sourceCompetitionId
  const hasGroup = !!input.sourceGroupId

  if (hasComp && hasGroup) {
    throw new InviteSourceValidationError(
      "Source cannot reference both a competition and a series",
    )
  }
  if (!hasComp && !hasGroup) {
    throw new InviteSourceValidationError(
      "Source must reference exactly one of a competition or a series",
    )
  }
  if (input.kind === COMPETITION_INVITE_SOURCE_KIND.COMPETITION && !hasComp) {
    throw new InviteSourceValidationError(
      'kind "competition" requires sourceCompetitionId',
    )
  }
  if (input.kind === COMPETITION_INVITE_SOURCE_KIND.SERIES && !hasGroup) {
    throw new InviteSourceValidationError(
      'kind "series" requires sourceGroupId',
    )
  }
}

// ============================================================================
// Queries
// ============================================================================

export async function listSourcesForChampionship(
  championshipCompetitionId: string,
): Promise<CompetitionInviteSource[]> {
  const db = getDb()
  return db
    .select()
    .from(competitionInviteSourcesTable)
    .where(
      eq(
        competitionInviteSourcesTable.championshipCompetitionId,
        championshipCompetitionId,
      ),
    )
    .orderBy(
      asc(competitionInviteSourcesTable.sortOrder),
      asc(competitionInviteSourcesTable.createdAt),
    )
}

export async function getSourceById(
  id: string,
): Promise<CompetitionInviteSource | null> {
  const db = getDb()
  const [row] = await db
    .select()
    .from(competitionInviteSourcesTable)
    .where(eq(competitionInviteSourcesTable.id, id))
    .limit(1)
  return row ?? null
}

// ============================================================================
// Mutations
// ============================================================================

function serializeDivisionMappings(
  mappings: DivisionMapping[] | null | undefined,
): string | null {
  if (!mappings || mappings.length === 0) return null
  return JSON.stringify(mappings)
}

export async function createSource(
  input: CreateSourceInput,
): Promise<CompetitionInviteSource> {
  assertSourceReferenceValid({
    kind: input.kind,
    sourceCompetitionId: input.sourceCompetitionId,
    sourceGroupId: input.sourceGroupId,
  })

  const db = getDb()
  const values = {
    championshipCompetitionId: input.championshipCompetitionId,
    kind: input.kind,
    sourceCompetitionId: input.sourceCompetitionId ?? null,
    sourceGroupId: input.sourceGroupId ?? null,
    directSpotsPerComp: input.directSpotsPerComp ?? null,
    globalSpots: input.globalSpots ?? null,
    divisionMappings: serializeDivisionMappings(input.divisionMappings),
    sortOrder: input.sortOrder ?? 0,
    notes: input.notes ?? null,
  }

  const [inserted] = await db
    .insert(competitionInviteSourcesTable)
    .values(values)
    .$returningId()

  // MySQL insert returns only the id; re-read for canonical shape.
  const row = await getSourceById(inserted.id)
  if (!row) {
    throw new Error("Source was inserted but could not be re-read")
  }
  return row
}

export async function updateSource(
  input: UpdateSourceInput,
): Promise<CompetitionInviteSource> {
  const existing = await getSourceById(input.id)
  if (!existing) {
    throw new InviteSourceValidationError("Source not found")
  }

  const nextKind = input.kind ?? existing.kind
  const nextComp =
    input.sourceCompetitionId !== undefined
      ? input.sourceCompetitionId
      : existing.sourceCompetitionId
  const nextGroup =
    input.sourceGroupId !== undefined
      ? input.sourceGroupId
      : existing.sourceGroupId

  assertSourceReferenceValid({
    kind: nextKind,
    sourceCompetitionId: nextComp,
    sourceGroupId: nextGroup,
  })

  const db = getDb()
  const patch: Record<string, unknown> = {}
  if (input.kind !== undefined) patch.kind = input.kind
  if (input.sourceCompetitionId !== undefined)
    patch.sourceCompetitionId = input.sourceCompetitionId
  if (input.sourceGroupId !== undefined)
    patch.sourceGroupId = input.sourceGroupId
  if (input.directSpotsPerComp !== undefined)
    patch.directSpotsPerComp = input.directSpotsPerComp
  if (input.globalSpots !== undefined) patch.globalSpots = input.globalSpots
  if (input.divisionMappings !== undefined) {
    patch.divisionMappings = serializeDivisionMappings(input.divisionMappings)
  }
  if (input.sortOrder !== undefined) patch.sortOrder = input.sortOrder
  if (input.notes !== undefined) patch.notes = input.notes

  await db
    .update(competitionInviteSourcesTable)
    .set(patch)
    .where(eq(competitionInviteSourcesTable.id, input.id))

  const row = await getSourceById(input.id)
  if (!row) {
    throw new Error("Source was updated but could not be re-read")
  }
  return row
}

export async function deleteSource(input: {
  id: string
  championshipCompetitionId: string
}): Promise<boolean> {
  const db = getDb()
  // Cascade delete the source's per-division allocation rows in the same
  // transaction (no FKs per PlanetScale convention — the cascade lives
  // here). Tx is the same primitive division capacity uses; PlanetScale
  // supports it.
  return await db.transaction(async (tx) => {
    // Verify the source belongs to the named championship before any
    // delete fires. Otherwise a caller authorized for championship A
    // could pass a sourceId from championship B and wipe its
    // allocation rows cross-tenant — the source-row delete below is
    // championship-scoped, but the allocations delete is keyed only by
    // sourceId.
    const [existing] = await tx
      .select({ id: competitionInviteSourcesTable.id })
      .from(competitionInviteSourcesTable)
      .where(
        and(
          eq(competitionInviteSourcesTable.id, input.id),
          eq(
            competitionInviteSourcesTable.championshipCompetitionId,
            input.championshipCompetitionId,
          ),
        ),
      )
      .limit(1)
    if (!existing) return false

    await tx
      .delete(competitionInviteSourceDivisionAllocationsTable)
      .where(
        eq(competitionInviteSourceDivisionAllocationsTable.sourceId, input.id),
      )
    await tx
      .delete(competitionInviteSourcesTable)
      .where(eq(competitionInviteSourcesTable.id, input.id))
    return true
  })
}

/**
 * Competition Invites Schema
 *
 * Tables powering ADR-0011 "Competition Invites" — the organizer-facing
 * qualification-source → roster → invite-round system.
 *
 * Phase 1 shipped `competition_invite_sources`. Phase 2 adds
 * `competition_invites` — the per-athlete invite row carrying the
 * email-locked claim token, status, and origin attribution. Rounds
 * (Phase 3) and email templates (Phase 4) follow.
 */
// @lat: [[competition-invites#Sources schema]]

import type { InferSelectModel } from "drizzle-orm"
import {
  datetime,
  index,
  int,
  mysqlTable,
  text,
  uniqueIndex,
  varchar,
} from "drizzle-orm/mysql-core"
import {
  commonColumns,
  createCompetitionInviteId,
  createCompetitionInviteSourceDivisionAllocationId,
  createCompetitionInviteSourceId,
} from "./common"

// ============================================================================
// Source Kinds
// ============================================================================

export const COMPETITION_INVITE_SOURCE_KIND = {
  COMPETITION: "competition",
  SERIES: "series",
} as const

export type CompetitionInviteSourceKind =
  (typeof COMPETITION_INVITE_SOURCE_KIND)[keyof typeof COMPETITION_INVITE_SOURCE_KIND]

// ============================================================================
// Competition Invite Sources
// ============================================================================

/**
 * A qualification source attached to a championship competition. Exactly one
 * of `sourceCompetitionId` / `sourceGroupId` is non-null — the `kind`
 * discriminator indicates which. Spot allocations describe how many invitees
 * this source contributes to the championship.
 *
 * Write-time constraints are enforced in helpers, not the DB, to match
 * PlanetScale conventions (no FKs).
 */
export const competitionInviteSourcesTable = mysqlTable(
  "competition_invite_sources",
  {
    ...commonColumns,
    id: varchar({ length: 255 })
      .primaryKey()
      .$defaultFn(() => createCompetitionInviteSourceId())
      .notNull(),
    // The competition receiving invites from this source.
    championshipCompetitionId: varchar({ length: 255 }).notNull(),
    // "competition" | "series"
    kind: varchar({ length: 20 })
      .$type<CompetitionInviteSourceKind>()
      .notNull(),
    // When kind = "competition".
    sourceCompetitionId: varchar({ length: 255 }),
    // When kind = "series". Logical reference to competitionGroupsTable.id.
    sourceGroupId: varchar({ length: 255 }),
    // For series: how many top-N per comp in the series get a direct slot.
    directSpotsPerComp: int(),
    // For series: how many additional spots come from the global leaderboard.
    // For single-comp: the total top-N that qualifies.
    globalSpots: int(),
    // JSON: [{ sourceDivisionId, championshipDivisionId, spots? }]
    divisionMappings: text(),
    // Display order of sources in the organizer sources tab.
    sortOrder: int().default(0).notNull(),
    // Organizer-visible free-text note about this source.
    notes: text(),
  },
  (table) => [
    index("competition_invite_sources_championship_sort_idx").on(
      table.championshipCompetitionId,
      table.sortOrder,
    ),
    index("competition_invite_sources_source_competition_idx").on(
      table.sourceCompetitionId,
    ),
    index("competition_invite_sources_source_group_idx").on(
      table.sourceGroupId,
    ),
  ],
)

export type CompetitionInviteSource = InferSelectModel<

/**
 * Championship Roster Computation
 *
 * `getChampionshipRoster` returns the union of every (sourceComp ×
 * sourceDivision) leaderboard for the championship's configured sources,
 * with each row tagged by the originating competition + division and the
 * athlete's email hydrated. The roster page renders this as a single
 * table with Competition + Division columns; client-side filters narrow
 * the view without round-tripping.
 *
 * Fan-out: a championship with K sources, each resolving to N
 * competitions × M divisions per competition, costs roughly K·N·M
 * leaderboard reads, fired in parallel. MVP organizers have 1–3 sources
 * with similarly small N/M, so the worst case is bounded under typical
 * usage. Leaderboards are cached on the public-facing render path.
 *
 * ADR-0012 Phase 6: per-(source, championshipDivision) cutoffs are
 * applied after leaderboards are fetched. The resolved allocation map
 * (`resolveSourceAllocations`) supplies the truncation N for each
 * `(sourceId, championshipDivisionId)`. Source-side `globalSpots` /
 * `directSpotsPerComp` act as defaults when no override row exists for
 * the championship division. See ADR-0012 "Allocation Resolution".
 */
// @lat: [[competition-invites#Roster computation]]

import { inArray } from "drizzle-orm"
import { getDb } from "@/db"
import {
  COMPETITION_INVITE_SOURCE_KIND,
  type CompetitionInviteSource,
  type CompetitionInviteSourceKind,
} from "@/db/schemas/competition-invites"
import { competitionsTable } from "@/db/schemas/competitions"
import { scalingLevelsTable } from "@/db/schemas/scaling"
import { parseCompetitionSettings } from "@/server-fns/competition-divisions-fns"
import type { ResolvedSourceAllocations } from "./allocations"
import { getCandidatesForSourceComp } from "./candidates"
import { type DivisionMapping, listSourcesForChampionship } from "./sources"

// ============================================================================
// Types
// ============================================================================

export interface RosterRow {
  /** 1-based rank within the source competition's division leaderboard. */
  sourcePlacement: number | null
  /** Source id that produced this row. */
  sourceId: string
  /** Source kind snapshot for UI tagging. */
  sourceKind: CompetitionInviteSourceKind
  /** Comp the athlete placed at. */
  sourceCompetitionId: string
  /** Display name of the source competition. */
  sourceCompetitionName: string
  /** Division id on the source competition. */
  sourceDivisionId: string
  /** Display label of the source division (e.g. "RX Men"). */
  sourceDivisionLabel: string
  /** Stable athlete identity. `userId` may be null if the leaderboard
   *  surfaced no user id (rare); `athleteName` is always present. */
  userId: string | null
  athleteName: string
  /** Email address for the athlete, resolved from `userTable` by `userId`.
   *  Null when the leaderboard surfaced no user id (rare) or the user
   *  has no email on file. */
  athleteEmail: string | null
  /** Invite-state columns — always null at this layer; the route attaches
   *  invite status via `listActiveInvitesFn` keyed by email. */
  inviteId: null
  inviteStatus: null
  roundId: null
  roundNumber: null
}

export interface GetChampionshipRosterInput {
  championshipId: string
}

// ============================================================================
// Internal helpers
// ============================================================================

interface SourceCompetitionRef {
  sourceId: string
  sourceKind: CompetitionInviteSourceKind
  competitionId: string
  competitionName: string
}

interface DivisionRef {
  competitionId: string
  competitionName: string
  divisionId: string
  divisionLabel: string
  sourceId: string
  sourceKind: CompetitionInviteSourceKind
}

interface ChampionshipDivisionInfo {
  id: string

      scalingGroupId: scalingLevelsTable.scalingGroupId,
      position: scalingLevelsTable.position,
    })
    .from(scalingLevelsTable)
    .where(inArray(scalingLevelsTable.scalingGroupId, allGroupIds))

  const levelsByGroup = new Map<
    string,
    Array<{ id: string; label: string; position: number }>
  >()
  for (const lvl of levels) {
    const arr = levelsByGroup.get(lvl.scalingGroupId) ?? []
    arr.push({ id: lvl.id, label: lvl.label, position: lvl.position })
    levelsByGroup.set(lvl.scalingGroupId, arr)
  }
  for (const arr of levelsByGroup.values()) {
    arr.sort((a, b) => a.position - b.position)
  }

  const out: DivisionRef[] = []
  for (const comp of comps) {
    const sgid = scalingGroupByComp.get(comp.competitionId)
    if (!sgid) continue
    const compLevels = levelsByGroup.get(sgid) ?? []
    for (const lvl of compLevels) {
      out.push({
        competitionId: comp.competitionId,
        competitionName: comp.competitionName,
        divisionId: lvl.id,
        divisionLabel: lvl.label,
        sourceId: comp.sourceId,
        sourceKind: comp.sourceKind,
      })
    }
  }
  return out
}

/**
 * Compute the cutoff (max number of qualifying placements) for a
 * leaderboard fetched for `(source, sourceCompetitionId, sourceDivisionId)`.
 *
 * Single-comp source: the cutoff is the resolved per-(source,
 * championshipDivision) value. Override present → uses override; absent
 * → uses the source's `globalSpots` default (applied per division).
 *
 * Series source: today the leaderboard fan-out yields one entry per
 * (seriesComp × division). The per-comp "direct" line uses
 * `directSpotsPerComp` as the default; when an override exists for the
 * championship division the override is the *total* number of direct
 * qualifiers for that division across the *whole series* — not per
 * comp. We can't faithfully redistribute that across comps without
 * series-leaderboard context (which row from comp A vs comp B counts
 * toward the global pool), so series with overrides keeps the current
 * full-leaderboard behavior and lets downstream UI / the
 * `divisionAllocationTotals` denominator surface the discrepancy.
 *
 * TODO(ADR-0012 Phase 6): split direct vs. global tiers cleanly for
 * series sources with division-level overrides; today the override is
 * honored on the per-division *denominator* (Sent tab) but not on the
 * per-comp leaderboard truncation here. See ADR-0012 "Allocation
 * Resolution" — the global block is still the safe fallback because it
 * never *adds* invalid qualifying rows; it can only over-include rows
 * the organizer must filter manually.
 *
 * Returns `null` when no cutoff applies (i.e. include every row).
 */
function computeCutoffForLeaderboard(args: {
  source: CompetitionInviteSource
  sourceDivisionId: string
  sourceDivisionLabel: string
  championshipDivisions: ReadonlyArray<ChampionshipDivisionInfo>
  resolved: ResolvedSourceAllocations
  divisionMappings: DivisionMapping[]
}): number | null {
  if (args.source.kind === COMPETITION_INVITE_SOURCE_KIND.SERIES) {
    // Series fallback: keep all rows. Per-comp direct truncation is a
    // future improvement (TODO above) — until the (direct, global)
    // tiers are split, returning the full leaderboard is the safer
    // path because it can only over-include candidate rows the
    // organizer manually filters, never silently drop a qualifier.
    return null
  }

  // Single-comp source: cutoff is the resolved spots for the mapped
  // championship division. If we can't infer the championship division,
  // fall back to no truncation so we don't accidentally drop qualifying
  // athletes — the downstream UI still surfaces the correct denominator.
  const championshipDivisionId = mapSourceDivisionToChampionship({
    sourceDivisionId: args.sourceDivisionId,
    sourceDivisionLabel: args.sourceDivisionLabel,
    divisionMappings: args.divisionMappings,
    championshipDivisions: args.championshipDivisions,
  })
  if (championshipDivisionId === null) return null
  const spots = args.resolved.byDivision[championshipDivisionId]
  if (spots === undefined) return null
  return spots
}

// ============================================================================
// Main entry
// ============================================================================

export async function getChampionshipRoster(
  input: GetChampionshipRosterInput,
): Promise<{ rows: RosterRow[] }> {
  const { refs: comps } = await resolveSourceCompetitions(input.championshipId)
  if (comps.length === 0) return { rows: [] }

  const divisionRefs = await resolveDivisionRefs(comps)
  if (divisionRefs.length === 0) return { rows: [] }

  // Fan out per (sourceComp × division) candidate fetches in parallel.
  // `getCandidatesForSourceComp` is purpose-built for this surface: it
  // returns active registrations directly, with no heat / event-status /
  // publication gating. The roster used to call `getCompetitionLeaderboard`
  // here, which silently dropped divisions whose athletes hadn't been
  // heat-assigned — see docs/bugs/0001-invite-candidates-missing-divisions.md.
  //

"use client"

/**
 * Invite Sources List — organizer-visible roster of all qualification
 * sources feeding the championship, plus an allocated-spots summary card
 * (matches `project/invites/sources.jsx` modulo visual polish).
 */

import type React from "react"
import { Layers, Trophy } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import type { CompetitionInviteSource } from "@/db/schemas/competition-invites"

interface InviteSourcesListProps {
  sources: CompetitionInviteSource[]
  competitionNamesById: Record<string, string>
  seriesNamesById: Record<string, string>
  /** Number of competitions per series groupId, used to scale
   *  `directSpotsPerComp` into a total allocation. */
  seriesCompCountsById?: Record<string, number>
  /** ADR-0012: resolved per-(source, championshipDivision) allocation
   *  map, summed per source. When supplied, each card's "qualifying
   *  spots" line uses the authoritative resolved total instead of the
   *  source-level scalar math. Optional so older callers (and tests)
   *  keep working with the local fallback. */
  allocationsBySourceByDivision?: Record<string, Record<string, number>>
  /** Championship divisions in display order — used to render the
   *  per-division preview row under each source card. Optional; the
   *  preview is hidden when omitted. */
  championshipDivisions?: ReadonlyArray<{ id: string; label: string }>
  onEdit?: (source: CompetitionInviteSource) => void
  onDelete?: (source: CompetitionInviteSource) => void
  onAdd?: () => void
  /** Optional render-prop for extra content inside a source card (used to
   *  drop in the series per-comp + global sub-tabs). */
  renderSourceExtras?: (source: CompetitionInviteSource) => React.ReactNode
}

function allocatedSpotsFor(
  source: CompetitionInviteSource,
  seriesCompCountsById: Record<string, number>,
): number {
  if (source.kind === "series") {
    const compCount = source.sourceGroupId
      ? (seriesCompCountsById[source.sourceGroupId] ?? 0)
      : 0
    return (
      (source.directSpotsPerComp ?? 0) * compCount + (source.globalSpots ?? 0)
    )
  }
  return source.globalSpots ?? 0
}

export function InviteSourcesList({
  sources,
  competitionNamesById,
  seriesNamesById,
  seriesCompCountsById = {},
  allocationsBySourceByDivision,
  championshipDivisions,
  onEdit,
  onDelete,
  onAdd,
  renderSourceExtras,
}: InviteSourcesListProps) {
  // Authoritative resolved total per source. Falls back to the local
  // scalar math when the loader hasn't supplied the resolved map (older
  // callers + unit tests).
  const resolvedTotalFor = (source: CompetitionInviteSource): number => {
    const map = allocationsBySourceByDivision?.[source.id]
    if (map) {
      return Object.values(map).reduce((a, b) => a + b, 0)
    }
    return allocatedSpotsFor(source, seriesCompCountsById)
  }

  const totalAllocated = sources.reduce(
    (acc, s) => acc + resolvedTotalFor(s),
    0,
  )

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle>Qualification sources</CardTitle>
            <CardDescription>
              {sources.length === 0
                ? "No sources configured yet."
                : `${sources.length} source${
                    sources.length === 1 ? "" : "s"
                  } · ${totalAllocated} qualifying spots allocated.`}
            </CardDescription>
          </div>
