                      <div className="text-xs uppercase text-muted-foreground">
                        Direct qualifiers
                      </div>
                      <div className="mt-1 text-sm">
                        Top{" "}
                        <span className="font-semibold">
                          {source.directSpotsPerComp ?? 0}
                        </span>{" "}
                        of each throwdown directly invited.
                      </div>
                    </div>
                    <div>
                      <div className="text-xs uppercase text-muted-foreground">
                        Global spots
                      </div>
                      <div className="mt-1 text-sm">
                        <span className="font-semibold">
                          {source.globalSpots ?? 0}
