/**
 * Load all per-(source, championship-division) allocation rows for a
 * championship's sources. Returns one flat list — callers typically index
 * by `sourceId` themselves.
 *
 * Implemented as a join from `competition_invite_sources` rather than a
 * fan-out: one query, one result, the `championshipDivisionId` index on
 * the allocation table makes the per-division grouping cheap downstream.
 */
export async function listAllocationsForChampionship(args: {
  championshipCompetitionId: string
}): Promise<CompetitionInviteSourceDivisionAllocation[]> {
  const db = getDb()

  const sourceIdRows = await db
    .select({ id: competitionInviteSourcesTable.id })
    .from(competitionInviteSourcesTable)
    .where(
      eq(
        competitionInviteSourcesTable.championshipCompetitionId,
        args.championshipCompetitionId,
      ),
    )

  if (sourceIdRows.length === 0) return []

  const sourceIds = sourceIdRows.map((r) => r.id)

  return db
    .select()
    .from(competitionInviteSourceDivisionAllocationsTable)
    .where(
      inArray(
        competitionInviteSourceDivisionAllocationsTable.sourceId,
        sourceIds,
      ),
    )
}

"use client"

/**
 * Invite Source Form — create / edit a single source.
 *
 * Two kinds: single-competition (requires sourceCompetitionId) and series
 * (requires sourceGroupId). Both kinds share `globalSpots` as the per-
 * division qualifying-spot default (e.g. 1 = "top 1 finisher per
 * division"); per-division overrides live on the source-detail page.
 * The form-level validator mirrors the server-side helper: exactly one
 * of sourceCompetitionId / sourceGroupId.
 */

import { standardSchemaResolver } from "@hookform/resolvers/standard-schema"
import { useForm } from "react-hook-form"
import { z } from "zod"
import { Button } from "@/components/ui/button"
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import {
  COMPETITION_INVITE_SOURCE_KIND,
  type CompetitionInviteSource,
} from "@/db/schemas/competition-invites"

export const inviteSourceFormSchema = z
  .object({
    kind: z.enum([
      COMPETITION_INVITE_SOURCE_KIND.COMPETITION,
      COMPETITION_INVITE_SOURCE_KIND.SERIES,
    ]),
    sourceCompetitionId: z.string().optional(),
    sourceGroupId: z.string().optional(),
    globalSpots: z.number().int().positive().optional(),
    notes: z.string().max(2000).optional(),
  })
  .superRefine((val, ctx) => {
    const hasComp = !!val.sourceCompetitionId
    const hasGroup = !!val.sourceGroupId
    if (hasComp === hasGroup) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Pick exactly one source — a competition or a series",
        path: ["sourceCompetitionId"],
      })
    }
    if (val.kind === "competition" && !hasComp) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Single-competition source needs a competition",
        path: ["sourceCompetitionId"],
      })
    }
    if (!val.globalSpots) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Set the top-N qualifying spots per division",
        path: ["globalSpots"],
      })
    }
    if (val.kind === "series" && !hasGroup) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Series source needs a series",
        path: ["sourceGroupId"],
      })
    }
  })

export type InviteSourceFormValues = {
  kind: "competition" | "series"
  sourceCompetitionId?: string
  sourceGroupId?: string
  globalSpots?: number
  notes?: string
}

interface InviteSourceFormProps {
  defaultValues?: Partial<CompetitionInviteSource>
  competitionOptions: Array<{ id: string; name: string }>
  seriesOptions: Array<{ id: string; name: string }>
  onSubmit: (values: InviteSourceFormValues) => Promise<void> | void
  onCancel?: () => void
  submitLabel?: string
}

export function InviteSourceForm({
  defaultValues,
  competitionOptions,
  seriesOptions,
  onSubmit,
  onCancel,
  submitLabel = "Save source",
}: InviteSourceFormProps) {
  const form = useForm<InviteSourceFormValues, unknown, InviteSourceFormValues>({
    resolver: standardSchemaResolver(inviteSourceFormSchema),
    defaultValues: {
      kind:
        (defaultValues?.kind as InviteSourceFormValues["kind"]) ?? "competition",
      sourceCompetitionId: defaultValues?.sourceCompetitionId ?? undefined,
      sourceGroupId: defaultValues?.sourceGroupId ?? undefined,
      globalSpots: defaultValues?.globalSpots ?? undefined,
      notes: defaultValues?.notes ?? undefined,
    },
  })
  const kind = form.watch("kind")

  return (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(async (v) => {
          await onSubmit(v)
        })}
        className="space-y-4"
      >
        <FormField
          control={form.control}
          name="kind"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Source kind</FormLabel>
              <Select onValueChange={field.onChange} value={field.value}>
                <FormControl>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                </FormControl>
                <SelectContent>
                  <SelectItem value="competition">Single competition</SelectItem>
                  <SelectItem value="series">Series</SelectItem>
                </SelectContent>
              </Select>
              <FormMessage />
            </FormItem>
          )}
        />

        {kind === "competition" ? (
          <FormField
            control={form.control}
            name="sourceCompetitionId"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Source competition</FormLabel>
                <Select
                  onValueChange={field.onChange}
                  value={field.value ?? undefined}
                >
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Pick a competition" />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    {competitionOptions.map((c) => (
                      <SelectItem key={c.id} value={c.id}>
                        {c.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />
        ) : (
          <FormField
            control={form.control}
            name="sourceGroupId"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Series</FormLabel>
                <Select
                  onValueChange={field.onChange}
                  value={field.value ?? undefined}
                >
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Pick a series" />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    {seriesOptions.map((g) => (
                      <SelectItem key={g.id} value={g.id}>
                        {g.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />
        )}

        <FormField
          control={form.control}
          name="globalSpots"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Top N qualifies per division</FormLabel>
              <FormControl>
                <Input
                  type="number"
                  min={1}
                  value={field.value ?? ""}
                  onChange={(e) =>
                    field.onChange(
                      e.target.value === "" ? undefined : Number(e.target.value),
                    )
                  }
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="notes"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Notes</FormLabel>
              <FormControl>
                <Textarea {...field} value={field.value ?? ""} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <div className="flex justify-end gap-2">
          {onCancel ? (
            <Button type="button" variant="outline" onClick={onCancel}>
              Cancel
            </Button>
          ) : null}
          <Button type="submit" disabled={form.formState.isSubmitting}>
            {submitLabel}
          </Button>
        </div>
      </form>
    </Form>
  )
}

